#include <stdio.h>

int upperBound(int *nums, int n, int x) {
    int low = 0, high = n;
    while (low < high) {
        int mid = low + (high - low) / 2;
        if (nums[mid] <= x)
            low = mid + 1;
        else
            high = mid;
    }
    return low;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        int nums[n];
        for (int i = 0; i < n; ++i) scanf("%d", &nums[i]);
        int x;
        scanf("%d", &x);
        printf("%d\n", upperBound(nums, n, x));
    }
    return 0;
}

